<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  :root {
    --bg: #12141c;
    --board-bg: #1c1f2b;
    --cell-bg: #2a2e3d;
    --text: #e8eaf0;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 20px;
    padding: 20px;
  }
  h1 {
    margin: 0;
    font-size: 48px;
    letter-spacing: 2px;
  }
  .topbar {
    display: flex;
    align-items: center;
    gap: 16px;
  }
  .score-box {
    background: var(--board-bg);
    border-radius: 8px;
    padding: 8px 18px;
    text-align: center;
  }
  .score-label {
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 1px;
    opacity: 0.6;
  }
  #score {
    font-size: 24px;
    font-weight: 700;
  }
  #reset {
    background: #6c5ce7;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 12px 20px;
    font-size: 15px;
    font-weight: 600;
    cursor: pointer;
  }
  #reset:hover { background: #5a4bd4; }
  #board {
    background: var(--board-bg);
    border-radius: 10px;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(4, 1fr);
    gap: 12px;
    width: min(90vw, 440px);
    height: min(90vw, 440px);
  }
  .cell {
    background: var(--cell-bg);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 32px;
    font-weight: 700;
    color: var(--text);
    user-select: none;
  }
  .cell[data-v="0"] { color: transparent; }
  .cell[data-v="2"]    { background: #3a3f52; }
  .cell[data-v="4"]    { background: #445; }
  .cell[data-v="8"]    { background: #d9822b; color:#fff; }
  .cell[data-v="16"]   { background: #d97014; color:#fff; }
  .cell[data-v="32"]   { background: #e5533b; color:#fff; }
  .cell[data-v="64"]   { background: #e53b2b; color:#fff; }
  .cell[data-v="128"]  { background: #e5c53b; color:#fff; font-size:28px; }
  .cell[data-v="256"]  { background: #e5bd2b; color:#fff; font-size:28px; }
  .cell[data-v="512"]  { background: #e5b81b; color:#fff; font-size:28px; }
  .cell[data-v="1024"] { background: #edc531; color:#fff; font-size:22px; }
  .cell[data-v="2048"] { background: #edc531; color:#fff; font-size:22px; }
  .hint { opacity: 0.5; font-size: 13px; }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="topbar">
    <div class="score-box">
      <div class="score-label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div class="hint">Use arrow keys to move</div>

<script>
(function () {
  const SIZE = 4;
  let grid = emptyGrid();
  let scoreVal = 0;

  const boardEl = document.getElementById('board');
  const scoreEl = document.getElementById('score');
  const cells = [];

  // build cell elements
  for (let i = 0; i < SIZE * SIZE; i++) {
    const c = document.createElement('div');
    c.className = 'cell';
    boardEl.appendChild(c);
    cells.push(c);
  }

  function emptyGrid() {
    return Array.from({ length: SIZE }, () => new Array(SIZE).fill(0));
  }

  function emptyCells() {
    const out = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) out.push([r, c]);
    return out;
  }

  function spawn() {
    const empties = emptyCells();
    if (empties.length === 0) return false;
    const [r, c] = empties[Math.floor(Math.random() * empties.length)];
    grid[r][c] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  // Slide + merge a single row to the left. Returns {row, gained}.
  function slideLine(line) {
    const nums = line.filter(v => v !== 0);
    const out = [];
    let gained = 0;
    for (let i = 0; i < nums.length; i++) {
      if (i + 1 < nums.length && nums[i] === nums[i + 1]) {
        const merged = nums[i] * 2;
        out.push(merged);
        gained += merged;
        i++; // skip next, merged at most once
      } else {
        out.push(nums[i]);
      }
    }
    while (out.length < SIZE) out.push(0);
    return { row: out, gained };
  }

  function rotateCW(g) {
    const n = emptyGrid();
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        n[c][SIZE - 1 - r] = g[r][c];
    return n;
  }
  function rotateCCW(g) {
    const n = emptyGrid();
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        n[SIZE - 1 - c][r] = g[r][c];
    return n;
  }
  function reverseRows(g) {
    return g.map(row => row.slice().reverse());
  }

  function equal(a, b) {
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (a[r][c] !== b[r][c]) return false;
    return true;
  }

  // Perform a move without spawning. Returns {moved, gained}.
  function doMove(dir) {
    let work = grid;
    // Transform so the move becomes "left"
    if (dir === 'up') work = rotateCCW(work);
    else if (dir === 'down') work = rotateCW(work);
    else if (dir === 'right') work = reverseRows(work);

    let gained = 0;
    const slid = work.map(row => {
      const res = slideLine(row);
      gained += res.gained;
      return res.row;
    });

    // Transform back
    let result = slid;
    if (dir === 'up') result = rotateCW(result);
    else if (dir === 'down') result = rotateCCW(result);
    else if (dir === 'right') result = reverseRows(result);

    const moved = !equal(grid, result);
    if (moved) grid = result;
    return { moved, gained };
  }

  function move(dir) {
    const valid = ['left', 'right', 'up', 'down'];
    if (!valid.includes(dir)) return false;
    const { moved, gained } = doMove(dir);
    if (moved) {
      scoreVal += gained;
      spawn();
      render();
    }
    return moved;
  }

  function reset() {
    grid = emptyGrid();
    scoreVal = 0;
    spawn();
    spawn();
    render();
  }

  function setBoard(arr) {
    const g = emptyGrid();
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        g[r][c] = Number(arr[r][c]) || 0;
    grid = g;
    render();
  }

  function boardCopy() {
    return grid.map(row => row.slice());
  }

  function render() {
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const v = grid[r][c];
        const el = cells[r * SIZE + c];
        el.textContent = v === 0 ? '' : String(v);
        el.setAttribute('data-v', String(v));
      }
    }
    scoreEl.textContent = String(scoreVal);
  }

  document.addEventListener('keydown', (e) => {
    const map = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down',
    };
    const dir = map[e.key];
    if (dir) {
      e.preventDefault();
      move(dir);
    }
  });

  document.getElementById('reset').addEventListener('click', reset);

  window.game = {
    size: SIZE,
    reset,
    move,
    board: boardCopy,
    setBoard,
    score: () => scoreVal,
  };

  reset();
})();
</script>
</body>
</html>
